import { useState } from "react";

function App() {
    const [resumeText, setResumeText] = useState("");
    const [jobDescription, setJobDescription] = useState("");
    const [analysis, setAnalysis] = useState(null);

    const analyzeResume = async () => {
        if (resumeText.trim() === "") {
            setAnalysis({
                score: 0,
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Please paste your resume content first."]
            });
            return;
        }

        try {
            const response = await fetch("http://localhost:5000/analyze", {
                method: "POST",
                headers: {
                    "Content-Type": "application/json"
                },
                body: JSON.stringify({ resumeText, jobDescription })
            });

            const data = await response.json();
            setAnalysis(data);
        } catch (error) {
            setAnalysis({
                score: 0,
                matchedSkills: [],
                missingSkills: [],
                suggestions: ["Error connecting to backend."]
            });
        }
    };

    return (
        <div
            style={{
                minHeight: "100vh",
                backgroundColor: "#f4f7fb",
                display: "flex",
                justifyContent: "center",
                alignItems: "center",
                fontFamily: "Arial, sans-serif",
                padding: "20px"
            }}
        >
            <div
                style={{
                    backgroundColor: "white",
                    padding: "30px",
                    borderRadius: "12px",
                    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
                    width: "800px"
                }}
            >
                <h1 style={{ textAlign: "center" }}>AI Resume Analyzer 🚀</h1>
                <p style={{ textAlign: "center" }}>
                    Paste your resume and a job description to check your match.
                </p>

                <h3>Resume</h3>
                <textarea
                    placeholder="Paste your resume content here..."
                    value={resumeText}
                    onChange={(e) => setResumeText(e.target.value)}
                    style={{
                        width: "100%",
                        height: "180px",
                        padding: "12px",
                        marginTop: "10px",
                        borderRadius: "8px",
                        border: "1px solid #ccc",
                        resize: "none",
                        fontSize: "14px"
                    }}
                />

                <h3 style={{ marginTop: "20px" }}>Job Description</h3>
                <textarea
                    placeholder="Paste the job description here..."
                    value={jobDescription}
                    onChange={(e) => setJobDescription(e.target.value)}
                    style={{
                        width: "100%",
                        height: "150px",
                        padding: "12px",
                        marginTop: "10px",
                        borderRadius: "8px",
                        border: "1px solid #ccc",
                        resize: "none",
                        fontSize: "14px"
                    }}
                />

                <div style={{ textAlign: "center", marginTop: "20px" }}>
                    <button
                        onClick={analyzeResume}
                        style={{
                            backgroundColor: "#007bff",
                            color: "white",
                            border: "none",
                            padding: "12px 20px",
                            borderRadius: "8px",
                            cursor: "pointer",
                            fontSize: "16px"
                        }}
                    >
                        Analyze Match
                    </button>
                </div>

                {analysis && (
                    <div style={{ marginTop: "30px" }}>
                        <div
                            style={{
                                backgroundColor: "#eef4ff",
                                padding: "15px",
                                borderRadius: "8px",
                                marginBottom: "15px"
                            }}
                        >
                            <h3>Match Score: {analysis.score}/100</h3>
                        </div>

                        <div
                            style={{
                                backgroundColor: "#f8f9fa",
                                padding: "15px",
                                borderRadius: "8px",
                                marginBottom: "15px"
                            }}
                        >
                            <h3>Matched Skills</h3>
                            <p>
                                {analysis.matchedSkills.length
                                    ? analysis.matchedSkills.join(", ")
                                    : "No matched skills found"}
                            </p>
                        </div>

                        <div
                            style={{
                                backgroundColor: "#fff8e1",
                                padding: "15px",
                                borderRadius: "8px",
                                marginBottom: "15px"
                            }}
                        >
                            <h3>Missing Skills</h3>
                            <p>
                                {analysis.missingSkills.length
                                    ? analysis.missingSkills.join(", ")
                                    : "No missing skills"}
                            </p>
                        </div>

                        <div
                            style={{
                                backgroundColor: "#fcebea",
                                padding: "15px",
                                borderRadius: "8px"
                            }}
                        >
                            <h3>Suggestions</h3>
                            <ul>
                                {analysis.suggestions.map((item, index) => (
                                    <li key={index}>{item}</li>
                                ))}
                            </ul>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
}

export default App;
